function normalizeReading(item){return {type:clean(item.type,36)||'Local reading',title:clean(item.title,72)||clean(item.type,36)||'Local reading',message:clean(item.message,240)||'left a luminous mark',region:regions[item.region]?item.region:currentRegion,sigil:['star','seed','coral','moon','mirror','spark'].includes(item.sigil)?item.sigil:'spark',x:clampCoord(item.x),y:clampCoord(item.y),createdAt:item.createdAt||new Date().toISOString()}}
