function renderReadingHistory(){const list=$('#readingHistoryList'),clear=$('#clearReadingHistory');if(!list)return;if(clear)clear.disabled=!readingHistory.length;list.innerHTML=readingHistory.length?readingHistory.slice().reverse().map((r,i)=>`<article class="reading-entry"><b>${r.type}: ${r.title}</b><small>${r.region} · ${r.sigil} · ${r.x}, ${r.y}</small><p>${r.message}</p><button class="button subtle small carry-reading" type="button" data-i="${readingHistory.length-1-i}">Carry again</button></article>`).join(''):'<article class="reading-entry empty"><b>No private readings saved yet.</b><p>Carry a forecast, route, cross-reference, notebook note, annex room, or word seed into the composer and it will appear here locally.</p></article>';$$('.carry-reading').forEach(btn=>btn.onclick=()=>applyReadingHistory(Number(btn.dataset.i)))}
