const expansePositions={
 'Atrium':[600,420],'Weather Loom':[230,160],'Memory Orchard':[970,220],'Mirror Lab':[235,665],'Signal Reef':[925,645],'Quiet Moon':[610,150]
};
const expanseColors={'Atrium':'var(--cyan)','Weather Loom':'var(--rose)','Memory Orchard':'var(--green)','Mirror Lab':'var(--violet)','Signal Reef':'var(--cyan)','Quiet Moon':'var(--gold)'};
