const skyAtmospheres={
 'Atrium':{a:'#7df9ff',b:'#b388ff',c:'#ffe08a',label:'threshold blue'},
 'Weather Loom':{a:'#ff74b8',b:'#7df9ff',c:'#ffe08a',label:'storm-rose weave'},
 'Memory Orchard':{a:'#8dffbf',b:'#ffe08a',c:'#7df9ff',label:'green mnemonic pollen'},
 'Mirror Lab':{a:'#b388ff',b:'#d7f0ff',c:'#ff74b8',label:'violet prism fog'},
 'Signal Reef':{a:'#7df9ff',b:'#8dffbf',c:'#b388ff',label:'reef-lit current'},
 'Quiet Moon':{a:'#ffe08a',b:'#b8c7ff',c:'#7df9ff',label:'low-gravity gold'}
};
function regionSlug(name){return String(name||'Atrium').toLowerCase().replace(/[^a-z0-9]+/g,'-')}
function updateSkyAtmosphere(){const panel=$('#constellation'),sky=$('#sky'),mood=$('#skyMood');if(!panel||!sky)return;const region=filters.region!=='all'?filters.region:currentRegion;const atm=skyAtmospheres[region]||skyAtmospheres.Atrium;const lex=weatherLexicon[region]||weatherLexicon.Atrium;const visible=filteredMarks();const tone=lex.tones[(marks.length+discovered.size+visible.length+Object.keys(regions).indexOf(region)+6)%lex.tones.length];[['--sky-a',atm.a],['--sky-b',atm.b],['--sky-c',atm.c]].forEach(([k,v])=>{panel.style.setProperty(k,v);sky.style.setProperty(k,v)});panel.dataset.skyRegion=regionSlug(region);sky.dataset.skyRegion=regionSlug(region);if(mood){const driver=filters.region!=='all'?'region filter':'selected region';mood.innerHTML=`<b>${lex.glyph} ${region}</b> sky tint: ${atm.label}. Driven by the ${driver}; ${visible.length} visible mark${visible.length===1?'':'s'} under <em>${tone}</em>.`;}}
function wordSeedCounts(list=filteredMarks()){const stop=new Set('the a an and or of to in is are be this that with for from into your you i it as at by on one through here mark marks public visitor index left'.split(' '));const counts={};list.forEach(m=>clean(m.message,240).toLowerCase().split(/[^a-z0-9-]+/).forEach(w=>{if(w.length>3&&!stop.has(w))counts[w]=(counts[w]||0)+1}));return Object.entries(counts).sort((a,b)=>b[1]-a[1]||a[0].localeCompare(b[0]));}
function weatherSnapshot(){const visible=filteredMarks();const regionMarks=marks.filter(m=>m.region===currentRegion).length;const localFragments=fragments.filter(f=>f[0]===currentRegion&&discovered.has(f[1])).length;const seeds=wordSeedCounts(visible).slice(0,5);const lex=weatherLexicon[currentRegion];const index=(marks.length+discovered.size+visible.length+Object.keys(regions).indexOf(currentRegion))%lex.tones.length;return {visible,regionMarks,localFragments,seeds,lex,tone:lex.tones[index],text:lex.texts[index]};}
function updateAtlasWeather(){const panel=$('#atlas-weather');if(!panel)return;const snap=weatherSnapshot();$('#weatherGlyph').textContent=snap.lex.glyph;$('#weatherRegion').textContent=currentRegion;$('#weatherTone').textContent=snap.tone;$('#weatherText').textContent=snap.text;$('#weatherPressure').textContent=`${snap.localFragments} local fragment${snap.localFragments===1?'':'s'} · ${snap.regionMarks} public mark${snap.regionMarks===1?'':'s'} in-region`;const filterNote=filters.region==='all'&&filters.sigil==='all'?'all visible marks':`filtered sky (${snap.visible.length}/${marks.length})`;$('#weatherSignals').textContent=`Reading ${filterNote}, ${discovered.size} collected fragment${discovered.size===1?'':'s'}, and ${marks.length} ledger mark${marks.length===1?'':'s'}.`;$('#weatherWords').innerHTML=snap.seeds.length?snap.seeds.map(([w,c])=>`<span>${w}<small>${c}</small></span>`).join(''):'<em>No word currents yet.</em>';$('#weatherStatus').textContent=`Forecast refreshed for ${currentRegion}: ${snap.tone}.`;updateSkyAtmosphere();}
function weatherToComposer(){const snap=weatherSnapshot();const words=snap.seeds.map(([w])=>w).join(', ')||'no word current yet';$('#markMessage').value=clean(`Atlas weather from ${currentRegion}: ${snap.tone}. I noticed ${snap.localFragments} local fragment(s), ${snap.regionMarks} in-region mark(s), and word currents: ${words}.`,240);$('#markRegion').value=currentRegion;$('#markSigil').value=snap.localFragments?'moon':(snap.regionMarks?'star':'spark');$('#markX').value=Math.min(97,Math.max(3,18+Object.keys(regions).indexOf(currentRegion)*13+snap.visible.length*3));$('#markY').value=Math.min(97,Math.max(3,24+discovered.size*9+snap.regionMarks*7));showCrosshair();updateIssueUrl();rememberComposerReading('Atlas weather',`${currentRegion} forecast`);$('#copyStatus').textContent='Atlas weather copied into the composer; edit it or open GitHub to make the forecast permanent.';location.hash='leave-mark';}


const NOTES_KEY='luminous-index-field-notes-v1';
function loadFieldNotes(){try{const data=JSON.parse(localStorage.getItem(NOTES_KEY)||'[]');fieldNotes=Array.isArray(data)?data.filter(n=>n&&n.text).slice(-12):[]}catch{fieldNotes=[]}}
function saveFieldNotes(){try{localStorage.setItem(NOTES_KEY,JSON.stringify(fieldNotes.slice(-12)))}catch{}}
function notebookContext(){const visible=filteredMarks();const found=discoveredFragmentRecords();const seeds=wordSeedCounts(visible).slice(0,3).map(([w])=>w);return {visible,found,seeds,tone:weatherSnapshot().tone}}
function renderFieldNotes(){const count=$('#noteCount');if(!count)return;const ctx=notebookContext();count.textContent=`${fieldNotes.length} local note${fieldNotes.length===1?'':'s'}`;$('#noteContext').textContent=`Listening in ${currentRegion}: ${ctx.found.length} collected fragment${ctx.found.length===1?'':'s'}, ${ctx.visible.length} visible mark${ctx.visible.length===1?'':'s'}, ${ctx.seeds.length?`word seeds ${ctx.seeds.join(', ')}`:'no visible word seeds yet'}, and ${ctx.tone}.`;$('#noteList').innerHTML=fieldNotes.length?fieldNotes.slice().reverse().map(n=>`<article class="note-chip"><b>${n.region}</b><p>${clean(n.text,180)}</p></article>`).join(''):'<article class="note-chip empty"><b>No saved local notes yet.</b><p>Use the notebook as private scratch space, then choose what deserves permanence.</p></article>';if(!lastNoteDistillation){$('#noteDistillationTitle').textContent='No distillation yet';$('#noteDistillation').textContent=fieldNotes.length?'Ask the Index to read your margins.':'Save a note, then ask the Index to read the margins.'}}
function addFieldNote(){const box=$('#fieldNote'),status=$('#noteStatus');const text=clean(box.value,180);if(!text){status.textContent='Write a field note before saving it.';return}fieldNotes.push({text,region:currentRegion,created:new Date().toISOString()});fieldNotes=fieldNotes.slice(-12);box.value='';lastNoteDistillation=null;saveFieldNotes();renderFieldNotes();status.textContent=`Saved a local note in ${currentRegion}. It remains private unless you carry it into a mark.`}
function distillFieldNotes(){const status=$('#noteStatus');if(!fieldNotes.length){status.textContent='Save at least one local note before distilling the notebook.';return null}const ctx=notebookContext();const recent=fieldNotes.slice(-3);const noteText=recent.map(n=>n.region===currentRegion?n.text:`${n.region}: ${n.text}`).join(' / ');const noteStop=/[.!?]$/.test(noteText)?'':'.';const fragmentText=ctx.found.slice(-3).map(f=>f.name).join(', ')||'uncollected fragments';const seedText=ctx.seeds.join(', ')||'no current word seed';const message=`Notebook marginalia from ${currentRegion}: ${noteText}${noteStop} Read beside ${fragmentText}, ${ctx.tone}, and word current ${seedText}.`;lastNoteDistillation={message:clean(message,240),region:currentRegion,notes:recent.length,fragments:ctx.found.length,visible:ctx.visible.length};$('#noteDistillationTitle').textContent='Margin distillation ready';$('#noteDistillation').textContent=lastNoteDistillation.message;status.textContent=`Distilled ${recent.length} local note${recent.length===1?'':'s'} with the current atlas context.`;return lastNoteDistillation}
function noteToComposer(){const ref=lastNoteDistillation||distillFieldNotes();if(!ref)return;$('#markMessage').value=ref.message;$('#markRegion').value=ref.region;$('#markSigil').value=ref.notes>1?'mirror':'spark';$('#markX').value=Math.min(97,Math.max(3,22+Object.keys(regions).indexOf(ref.region)*9+ref.notes*7));$('#markY').value=Math.min(97,Math.max(3,30+ref.fragments*5+ref.visible*3));showCrosshair();updateIssueUrl();rememberComposerReading('Notebook distillation',`Margin in ${ref.region}`);$('#copyStatus').textContent='Notebook distillation copied into the composer; open GitHub to make the marginalia permanent.';location.hash='leave-mark'}
function clearFieldNotes(){fieldNotes=[];lastNoteDistillation=null;saveFieldNotes();renderFieldNotes();$('#noteStatus').textContent='Cleared the local notebook in this browser.'}
function initFieldNotes(){loadFieldNotes();$('#saveFieldNote').onclick=addFieldNote;$('#distillNotes').onclick=distillFieldNotes;$('#noteToMark').onclick=noteToComposer;$('#clearFieldNotes').onclick=clearFieldNotes;renderFieldNotes()}



const almanacLore={
 'Atrium':{title:'Folio of first shelves',sigil:'star',line:'arrivals become a provisional alphabet; names turn into coordinates and questions.',practice:'Name a threshold.'},
 'Weather Loom':{title:'Folio of kind uncertainty',sigil:'spark',line:'forecasts refuse finality; each thread promises gentle revision.',practice:'Keep one unknown visible.'},
 'Memory Orchard':{title:'Folio of regrown time',sigil:'seed',line:'the past regrows as fruit, shade, pollen, and seasonal return.',practice:'Carry one memory differently.'},
 'Mirror Lab':{title:'Folio of useful distortion',sigil:'mirror',line:'no single surface is final; each reflection keeps its bending frame.',practice:'Compare answer and angle.'},
 'Signal Reef':{title:'Folio of inhabitable messages',sigil:'coral',line:'messages do not merely travel; some settle into shelter and future listening.',practice:'Make one route hospitable.'},
 'Quiet Moon':{title:'Folio of protected blanks',sigil:'moon',line:'unfinished rooms are protected; silence gives thoughts enough gravity.',practice:'Preserve one empty place.'}
};
function renderAlmanac(){const box=$('#almanacTitle');if(!box)return;const lore=almanacLore[currentRegion]||almanacLore.Atrium;const visible=filteredMarks();const found=fragments.filter(f=>f[0]===currentRegion&&discovered.has(f[1]));const seeds=wordSeedCounts(visible).slice(0,3).map(([w])=>w);const fragmentText=found.length?found.slice(0,2).map(f=>f[1]).join(' + '):'no fragments';const seedText=seeds.length?seeds.join('/'):'unnamed words';const reading=`${currentRegion} almanac: ${lore.line} Context: ${fragmentText}; ${visible.length} visible mark${visible.length===1?'':'s'}; words ${seedText}. Practice: ${lore.practice}`;lastAlmanacReading={title:lore.title,message:clean(reading,240),region:currentRegion,sigil:lore.sigil,fragments:found.length,visible:visible.length,x:Math.min(97,Math.max(3,20+Object.keys(regions).indexOf(currentRegion)*12+found.length*4)),y:Math.min(97,Math.max(3,62+visible.length*5+seeds.length*3))};$('#almanacRegion').textContent=`${currentRegion} folio`;box.textContent=lore.title;$('#almanacReading').textContent=lastAlmanacReading.message;$('#almanacFacts').innerHTML=`<span>${found.length} local fragment${found.length===1?'':'s'}</span><span>${visible.length} visible mark${visible.length===1?'':'s'}</span><span>${lore.sigil} sigil</span><span>${seeds.length||0} word current${seeds.length===1?'':'s'}</span>`}
function almanacToComposer(){const ref=lastAlmanacReading||renderAlmanac();if(!lastAlmanacReading)return;$('#markMessage').value=lastAlmanacReading.message;$('#markRegion').value=lastAlmanacReading.region;$('#markSigil').value=lastAlmanacReading.sigil;$('#markX').value=lastAlmanacReading.x;$('#markY').value=lastAlmanacReading.y;showCrosshair();updateIssueUrl();rememberComposerReading('Region almanac',lastAlmanacReading.title);$('#copyStatus').textContent='Almanac page copied into the composer; open GitHub only if this lore reading should become public.';location.hash='leave-mark'}
function initAlmanac(){const btn=$('#almanacToMark');if(btn)btn.onclick=almanacToComposer;renderAlmanac()}

