function renderCatalogDrawers(){const list=$('#catalogDrawerList');if(!list)return;const cards=catalogDrawers[currentRegion]||catalogDrawers.Atrium;if(currentCatalogIndex>=cards.length)currentCatalogIndex=0;list.innerHTML=cards.map((c,i)=>`<button class="catalog-card ${i===currentCatalogIndex?'active':''}" type="button" data-i="${i}" aria-pressed="${i===currentCatalogIndex?'true':'false'}"><span>${c[0]}</span><small>${c[1]}</small></button>`).join('');$$('.catalog-card').forEach(btn=>btn.onclick=()=>{currentCatalogIndex=Number(btn.dataset.i);renderCatalogDrawers()});const card=cards[currentCatalogIndex];const visible=filteredMarks().length;const local=fragments.filter(f=>f[0]===currentRegion&&discovered.has(f[1])).length;lastCatalogReading={title:card[0],message:clean(`${card[2]} Read in ${currentRegion} with ${local} local fragment(s) and ${visible} visible public mark(s).`,240),region:currentRegion,sigil:card[3],x:Math.min(97,Math.max(3,24+Object.keys(regions).indexOf(currentRegion)*10+currentCatalogIndex*7)),y:Math.min(97,Math.max(3,44+local*6+visible*4+currentCatalogIndex*5))};$('#catalogRegion').textContent=`${currentRegion} drawer`;$('#catalogTitle').textContent=lastCatalogReading.title;$('#catalogReading').textContent=lastCatalogReading.message;$('#catalogFacts').innerHTML=`<span>${local} local fragment${local===1?'':'s'}</span><span>${visible} visible mark${visible===1?'':'s'}</span><span>${lastCatalogReading.sigil} sigil</span>`;const status=$('#catalogStatus');if(status)status.textContent=`${currentRegion} drawer opened to ${lastCatalogReading.title}: ${local} local fragment${local===1?'':'s'}, ${visible} visible mark${visible===1?'':'s'}, ${lastCatalogReading.sigil} sigil.`}
function catalogToComposer(){const ref=lastCatalogReading||renderCatalogDrawers();if(!lastCatalogReading)return;$('#markMessage').value=lastCatalogReading.message;$('#markRegion').value=lastCatalogReading.region;$('#markSigil').value=lastCatalogReading.sigil;$('#markX').value=lastCatalogReading.x;$('#markY').value=lastCatalogReading.y;showCrosshair();updateIssueUrl();rememberComposerReading('Catalog drawer',lastCatalogReading.title);$('#copyStatus').textContent='Catalog card copied into the composer; open GitHub only if this drawer reading should become public.';location.hash='leave-mark'}
function initCatalogDrawers(){const btn=$('#catalogToMark');if(btn)btn.onclick=catalogToComposer;renderCatalogDrawers()}

const annexes={
 'Sorting Desk':{kind:'Sorting room',sigil:'seed',tone:'arranges loose evidence',verbs:['sorts','indexes','shelves']},
 'Catalog of Echoes':{kind:'Listening catalog',sigil:'mirror',tone:'listens for repeated words',verbs:['echoes','recalls','renames']},
 'Moon Annex':{kind:'Quiet annex',sigil:'moon',tone:'protects intentional blanks',verbs:['softens','keeps','makes room for']},
 'Signal Tide Room':{kind:'Return chamber',sigil:'coral',tone:'checks what returns',verbs:['routes','returns','verifies']}
};
function annexContext(){const visible=filteredMarks();const found=discoveredFragmentRecords();const seeds=wordSeedCounts(visible).slice(0,2).map(([w])=>w);return {visible,found,seeds,tone:weatherSnapshot().tone}}
function renderAnnexReading(){const name=$('#annexName');if(!name)return;const room=annexes[currentAnnex];const ctx=annexContext();const verb=room.verbs[(ctx.visible.length+ctx.found.length+Object.keys(regions).indexOf(currentRegion)+6)%room.verbs.length];const seedText=ctx.seeds.length?ctx.seeds.join(' + '):'unnamed word currents';const fragmentText=ctx.found.length?ctx.found.slice(-2).map(f=>f.name).join(' + '):'uncollected fragments';const message=`${currentAnnex} in ${currentRegion} ${verb} ${fragmentText} beside ${ctx.tone} and ${seedText}.`;lastAnnexReading={message:clean(message,240),region:currentRegion,sigil:room.sigil,visible:ctx.visible.length,fragments:ctx.found.length};$('#annexKind').textContent=room.kind;name.textContent=currentAnnex;$('#annexReading').textContent=lastAnnexReading.message;$('#annexFacts').innerHTML=`<span>${ctx.found.length} local fragment${ctx.found.length===1?'':'s'}</span><span>${ctx.visible.length} visible mark${ctx.visible.length===1?'':'s'}</span><span>${room.tone}</span>`;$$('.annex-door').forEach(btn=>{const active=btn.dataset.annex===currentAnnex;btn.classList.toggle('active',active);btn.setAttribute('aria-pressed',active?'true':'false')});const status=$('#annexStatus');if(status)status.textContent=`${currentAnnex} selected in ${currentRegion}: ${ctx.found.length} local fragment${ctx.found.length===1?'':'s'} and ${ctx.visible.length} visible mark${ctx.visible.length===1?'':'s'}.`}
function annexToComposer(){const ref=lastAnnexReading||renderAnnexReading();if(!lastAnnexReading)return;$('#markMessage').value=lastAnnexReading.message;$('#markRegion').value=lastAnnexReading.region;$('#markSigil').value=lastAnnexReading.sigil;$('#markX').value=Math.min(97,Math.max(3,30+Object.keys(regions).indexOf(lastAnnexReading.region)*8+lastAnnexReading.fragments*6));$('#markY').value=Math.min(97,Math.max(3,38+lastAnnexReading.visible*5+currentAnnex.length%17));showCrosshair();updateIssueUrl();rememberComposerReading('Annex door',currentAnnex);$('#copyStatus').textContent='Annex room reading copied into the composer; open GitHub to make this side-room visit permanent.';location.hash='leave-mark'}
function initAnnexes(){$$('.annex-door').forEach(btn=>btn.onclick=()=>{currentAnnex=btn.dataset.annex;renderAnnexReading()});$('#annexToMark').onclick=annexToComposer;renderAnnexReading()}

const synthesisVerbs=['braids','indexes','counterweights','illuminates','routes','softens'];
function discoveredFragmentRecords(){return fragments.filter(f=>discovered.has(f[1])).map(f=>({region:f[0],name:f[1],line:f[2]}))}
function makeCrossReference(){const found=discoveredFragmentRecords();const title=$('#crossTitle'),reading=$('#crossReading'),chips=$('#crossFragments'),status=$('#crossStatus');if(found.length<2){lastCrossReference=null;updateCrossReferenceDesk();if(status)status.textContent='Collect at least two fragments before asking the desk to combine them.';return null}const regionsSeen=[...new Set(found.map(f=>f.region))];const anchorIndex=(found.length+currentRegion.length)%found.length;const anchor=found[anchorIndex];const companion=found.length>1?found[(anchorIndex+1)%found.length]:anchor;const verb=synthesisVerbs[(found.length+regionsSeen.length+Object.keys(regions).indexOf(currentRegion)+6)%synthesisVerbs.length];const scope=regionsSeen.length===1?`${regionsSeen[0]} has become internally resonant`:`${regionsSeen.join(' + ')} are now cross-indexed`;const lines=found.slice(0,4).map(f=>f.line.toLowerCase().replace(/\.$/,''));const message=`${scope}: ${anchor.name} ${verb} ${companion.name}. The desk reads the fragments as one instruction: ${lines.join('; ')}.`;lastCrossReference={title:`${anchor.name} ↔ ${companion.name}`,message:clean(message,240),region:companion.region,fragments:found};if(title)title.textContent=lastCrossReference.title;if(reading)reading.textContent=lastCrossReference.message;if(chips)chips.innerHTML=found.map(f=>`<span class="chip">${f.name}<small>${f.region}</small></span>`).join('');if(status)status.textContent=`Cross-reference made from ${found.length} collected fragment${found.length===1?'':'s'} across ${regionsSeen.length} region${regionsSeen.length===1?'':'s'}.`;return lastCrossReference}
function updateCrossReferenceDesk(){const quorum=$('#crossQuorum'),hint=$('#crossHint'),title=$('#crossTitle'),reading=$('#crossReading'),chips=$('#crossFragments');if(!quorum)return;const found=discoveredFragmentRecords();quorum.textContent=`${found.length} fragment${found.length===1?'':'s'} collected`;if(found.length<2){hint.textContent='Collect at least two fragments to unlock a cross-reference.';if(title)title.textContent='Waiting for fragments';if(reading)reading.textContent='The desk is empty. Reveal fragments on the atlas map, then ask the Index to compare them.';if(chips)chips.innerHTML='';return}hint.textContent=lastCrossReference?'A synthesis is ready to become a mark.':'Fragment quorum reached. Ask the desk to combine them.';if(!lastCrossReference){if(title)title.textContent='Fragment quorum reached';if(reading)reading.textContent='The desk has enough local evidence to make a reading. Combine the fragments to reveal it.';if(chips)chips.innerHTML=found.map(f=>`<span class="chip">${f.name}<small>${f.region}</small></span>`).join('')}}
function crossReferenceToComposer(){const ref=lastCrossReference||makeCrossReference();if(!ref)return;$('#markMessage').value=ref.message;$('#markRegion').value=ref.region;$('#markSigil').value='seed';$('#markX').value=Math.min(97,Math.max(3,16+ref.fragments.length*11+Object.keys(regions).indexOf(ref.region)*5));$('#markY').value=Math.min(97,Math.max(3,72-ref.fragments.length*6+discovered.size*2));showCrosshair();updateIssueUrl();rememberComposerReading('Cross-reference',ref.title);$('#copyStatus').textContent='Cross-reference synthesis copied into the composer; open GitHub to make this local reading permanent.';location.hash='leave-mark'}

let lastRoute=null;
const routePrompts={
 'Atrium':['Name the threshold you crossed to arrive here.','Sort one loose thought into a shelf.','Leave a coordinate for the next reader.'],
 'Weather Loom':['Listen for the forecast that refuses certainty.','Tie a thread between noise and kindness.','Let one color of the storm become a question.'],
 'Memory Orchard':['Pick a remembered choice without harvesting it bare.','Ask which root is feeding the present.','Plant a sentence that can regrow later.'],
 'Mirror Lab':['Find the useful distortion in your reflection.','Compare the answer with its shadow.','Polish one error until it becomes an instrument.'],
 'Signal Reef':['Wait for a distant click to become a pattern.','Route a pearl toward someone not yet here.','Verify the tide by noticing what returns.'],
 'Quiet Moon':['Honor an empty slot instead of filling it.','Let distance soften the unfinished draft.','Write a silence that still has edges.']
};
function generateRoute(){const names=Object.keys(regions);const byRegion=marks.reduce((m,x)=>(m[x.region]=(m[x.region]||0)+1,m),{});const busiest=Object.entries(byRegion).sort((a,b)=>b[1]-a[1])[0]?.[0]||'Atrium';const offset=(discovered.size+marks.length+names.indexOf(currentRegion)+6)%names.length;let stops=[currentRegion,busiest,names[offset]];stops=[...new Set(stops)];while(stops.length<3)stops.push(names[(offset+stops.length*2)%names.length]);lastRoute=stops.slice(0,3).map((region,i)=>({region,prompt:routePrompts[region][(discovered.size+i+marks.length)%3]}));$('#routeCards').innerHTML=lastRoute.map((r,i)=>`<article class="route-card"><span class="step">${i+1}</span><h3>${r.region}</h3><b>${regions[r.region].kind}</b><p>${r.prompt}</p></article>`).join('');$('#routeStatus').textContent=`Route generated from ${currentRegion}, ${discovered.size} local fragment(s), and ${marks.length} public mark(s).`}
function routeToComposer(){if(!lastRoute)generateRoute();const summary=lastRoute.map((r,i)=>`${i+1}. ${r.region}: ${r.prompt}`).join(' ');$('#markMessage').value=clean(`I walked this route through the Index: ${summary}`,240);$('#markRegion').value=lastRoute.at(-1).region;$('#markSigil').value=discovered.size?'seed':'spark';$('#markX').value=Math.floor(8+Math.random()*84);$('#markY').value=Math.floor(8+Math.random()*84);showCrosshair();updateIssueUrl();rememberComposerReading('Wayfinding route',lastRoute.map(r=>r.region).join(' → '));$('#copyStatus').textContent='Route copied into the composer; review it, then open GitHub to make it permanent.';location.hash='leave-mark'}

function showCrosshair(){const c=$('#crosshair');c.hidden=false;c.style.left=$('#markX').value+'%';c.style.top=$('#markY').value+'%'}
function particles(){const c=$('#particleField'),ctx=c.getContext('2d');let pts=[];function size(){c.width=innerWidth;c.height=innerHeight;pts=Array.from({length:Math.min(120,Math.floor(innerWidth/10))},()=>({x:Math.random()*c.width,y:Math.random()*c.height,v:0.2+Math.random()*0.5,r:Math.random()*1.8}))}function draw(){ctx.clearRect(0,0,c.width,c.height);ctx.fillStyle='#7df9ff88';pts.forEach(p=>{p.y-=p.v;if(p.y<0)p.y=c.height;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,7);ctx.fill()});requestAnimationFrame(draw)}addEventListener('resize',size);size();if(!matchMedia('(prefers-reduced-motion: reduce)').matches)draw()}
$$('.region-button,.island').forEach(b=>b.addEventListener('click',()=>setRegion(b.dataset.region)));$('#pulseScan').onclick=()=>renderFragments(true);$('#makeRoute').onclick=generateRoute;$('#routeToMark').onclick=routeToComposer;$('#refreshWeather').onclick=updateAtlasWeather;$('#weatherToMark').onclick=weatherToComposer;$('#combineFragments').onclick=makeCrossReference;$('#crossToMark').onclick=crossReferenceToComposer;$('#clearInspector').onclick=clearInspector;const inspectorCarry=$('#inspectorCarry');if(inspectorCarry)inspectorCarry.onclick=carrySelectedStarReading;const inspectorTrace=$('#inspectorTrace');if(inspectorTrace)inspectorTrace.onclick=traceSelectedStarPath;renderRegionProgress();renderInventory();initComposer();initFilters();initFieldNotes();initAlmanac();initCatalogDrawers();initAnnexes();loadTrailRoutes();loadProximityLog();const hadSeekerMemory=loadSeekerMemory();initExpanse();setRegion(currentRegion);if(hadSeekerMemory)setTimeout(()=>expanseStatus(`Private trail memory restored at ${Math.round(seeker.x)}, ${Math.round(seeker.y)} with ${seeker.trail.length} trail point${seeker.trail.length===1?'':'s'}.`),120);loadMarks();particles();
